import { describe, expect, it, vi } from "vitest";
import { openStudioTo } from "./openStudioTo.js";
const mockMarkActiveStudioSessionEnded = vi.fn();
const mockMarkActiveStudioSessionClosed = vi.fn();
const mockReactivateActiveStudioSession = vi.fn();
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
const mockWriteActiveStudioSession = vi.fn();
const mockNavigateStudioAndAwaitAck = vi
    .fn()
    .mockResolvedValue({ acked: false, reason: "timeout" });
const mockPollLoginEvents = vi.fn();
vi.mock("../activeStudioSession.js", () => ({
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
    markActiveStudioSessionEnded: (...args) => mockMarkActiveStudioSessionEnded(...args),
    markActiveStudioSessionClosed: (...args) => mockMarkActiveStudioSessionClosed(...args),
    reactivateActiveStudioSession: (...args) => mockReactivateActiveStudioSession(...args),
    writeActiveStudioSession: (...args) => mockWriteActiveStudioSession(...args),
}));
vi.mock("./createStudioSession.js", () => ({
    createStudioSession: vi.fn().mockResolvedValue({
        sessionId: "new-session",
        serviceUrl: "https://test.invalid",
    }),
}));
vi.mock("../agentSessionChannel.js", () => ({
    navigateStudioAndAwaitAck: (...args) => mockNavigateStudioAndAwaitAck(...args),
    pollAgentSessionEvents: vi.fn().mockReturnValue(new Promise(() => { })),
    pollLoginEvents: (...args) => mockPollLoginEvents(...args),
}));
vi.mock("../browser.js", () => ({
    openChromelessWindow: vi.fn(),
}));
vi.mock("../frontmostApp.js", () => ({
    recordFocus: () => () => { },
}));
vi.mock("../config.js", () => ({
    saveCredentials: vi.fn(),
    getConfig: () => ({ serviceUrl: "https://test.invalid" }),
    hasCredentials: () => false,
}));
const mockWaitForSessionReady = vi.fn().mockResolvedValue(undefined);
vi.mock("./loginForSession.js", () => ({
    waitForSessionReady: (...args) => mockWaitForSessionReady(...args),
}));
describe("openStudioTo", () => {
    it("performs inline login when no apiKey is provided", async () => {
        mockPollLoginEvents.mockResolvedValueOnce("test-api-key");
        const onLoginRequired = vi.fn();
        const onAuthenticated = vi.fn();
        const result = await openStudioTo("/studio", {
            serviceUrl: "https://test.invalid",
            onLoginRequired,
            onAuthenticated,
        });
        expect(onLoginRequired).toHaveBeenCalledOnce();
        expect(onAuthenticated).toHaveBeenCalledOnce();
        expect(result.opened).toBe(true);
        const { openChromelessWindow } = await import("../browser.js");
        expect(openChromelessWindow).toHaveBeenCalledWith(expect.stringContaining("/studio/sign-in?redirect_url="));
        const signInUrl = openChromelessWindow.mock
            .calls[0][0];
        // onLoginRequired receives the same sign-in URL that was opened, so callers
        // can surface it to the user if the browser fails to open.
        expect(onLoginRequired).toHaveBeenCalledWith(expect.any(String), signInUrl);
        const redirectUrl = decodeURIComponent(signInUrl.split("redirect_url=")[1]);
        const pluginLoginCount = (redirectUrl.match(/pluginLogin=true/g) ?? [])
            .length;
        expect(pluginLoginCount).toBeLessThanOrEqual(1);
        expect(mockWriteActiveStudioSession).not.toHaveBeenCalled();
    });
    it("never deletes the session and asks (throws) when an active session does not respond", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        await expect(openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
        })).rejects.toThrow("Studio navigation failed: timeout");
        expect(mockMarkActiveStudioSessionEnded).not.toHaveBeenCalled();
    });
    it("asks (throws) even when the backend reports the session ended, if it was not explicitly ended", async () => {
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "session-ended",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        await expect(openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
        })).rejects.toThrow("Studio navigation failed: session-ended");
        expect(mockMarkActiveStudioSessionEnded).not.toHaveBeenCalled();
    });
    it("opens a fresh Studio without reconnecting when the record is closed (closedAt)", async () => {
        const navBefore = mockNavigateStudioAndAwaitAck.mock.calls.length;
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "closed-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            closedAt: "2026-01-01T00:05:00.000Z",
        });
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
        });
        // The window is gone, so no handshake is attempted at all.
        expect(mockNavigateStudioAndAwaitAck.mock.calls.length).toBe(navBefore);
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
    });
    it("reconnects an ended record (endedAt) and, when it fails, opens fresh silently", async () => {
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "timeout",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "ended-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            endedAt: "2026-01-01T00:05:00.000Z",
        });
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
        });
        // A deliberate end still attempts the reconnect, but a failure opens a fresh
        // window silently (no throw, no gate).
        expect(mockNavigateStudioAndAwaitAck).toHaveBeenCalled();
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
    });
    it("throws instead of reopening when an ended record's live tab blocks the navigation", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "blocked",
            blockedReason: "unsaved changes",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "ended-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            endedAt: "2026-01-01T00:05:00.000Z",
        });
        const createBefore = createStudioSession.mock
            .calls.length;
        await expect(openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
        })).rejects.toThrow("blocked");
        // endedAt only reopens silently when the tab is genuinely gone. A live tab
        // that refused the nav (blocked) must surface, not get a duplicate window.
        expect(createStudioSession.mock.calls.length).toBe(createBefore);
    });
    it("reactivates an ended record when its reconnect succeeds (reuse)", async () => {
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({ acked: true });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "ended-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            endedAt: "2026-01-01T00:05:00.000Z",
        });
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
        });
        // The window answered: reuse it AND clear the stale endedAt so pushActivity
        // stops skipping a session that is live again.
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("ended-session");
        expect(mockReactivateActiveStudioSession).toHaveBeenCalledWith("ended-session");
    });
    it("skips the existing record and opens fresh when forceNew is set", async () => {
        // forceNew bypasses readActiveStudioSession entirely, so no read mock is set
        // here (a leaked mockReturnValueOnce would desync later tests' read queue).
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
            forceNew: true,
        });
        expect(mockMarkActiveStudioSessionEnded).not.toHaveBeenCalled();
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
    });
    it("re-binds an explicit session id in a new window when it does not match the active pointer", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "other-session",
            serviceUrl: "https://test.invalid",
        });
        const navBefore = mockNavigateStudioAndAwaitAck.mock.calls.length;
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
            sessionId: "explicit-session",
        });
        // The explicit id does not match the locally tracked session, so there is no
        // live tab to reach: re-bind the id via createStudioSession without
        // navigating a stale session.
        expect(mockNavigateStudioAndAwaitAck.mock.calls.length).toBe(navBefore);
        expect(createStudioSession).toHaveBeenCalledWith(expect.objectContaining({ sessionId: "explicit-session" }));
        expect(result.opened).toBe(true);
    });
    it("reuses the existing tab when the explicit session id matches the active pointer", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({ acked: true });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "explicit-session",
            serviceUrl: "https://test.invalid",
        });
        const createBefore = createStudioSession.mock
            .calls.length;
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
            sessionId: "explicit-session",
        });
        // The explicit id matches the live session, so navigate it and reuse it
        // rather than opening a duplicate window.
        expect(mockNavigateStudioAndAwaitAck).toHaveBeenCalled();
        expect(createStudioSession.mock.calls.length).toBe(createBefore);
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("explicit-session");
    });
    it("reopens the explicit session in a new window when reaching the matched tab times out", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "timeout",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "explicit-session",
            serviceUrl: "https://test.invalid",
        });
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
            sessionId: "explicit-session",
        });
        // The matched tab did not respond (it was closed but the pointer was stale).
        // An explicit reconnect re-binds the id in a new window instead of throwing.
        // The record is never deleted; createStudioSession overwrites it with a fresh
        // active one, so it is not marked ended either.
        expect(mockNavigateStudioAndAwaitAck).toHaveBeenCalled();
        expect(mockMarkActiveStudioSessionEnded).not.toHaveBeenCalled();
        expect(createStudioSession).toHaveBeenCalledWith(expect.objectContaining({ sessionId: "explicit-session" }));
        expect(result.opened).toBe(true);
    });
    it("throws instead of re-binding when an explicit reconnect's live tab blocks the navigation", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "blocked",
            blockedReason: "unsaved changes",
        });
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "explicit-session",
            serviceUrl: "https://test.invalid",
        });
        const createBefore = createStudioSession.mock
            .calls.length;
        await expect(openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
            sessionId: "explicit-session",
        })).rejects.toThrow("blocked");
        // The tab is alive and actively refused this navigation, so surface that
        // rather than spawn a duplicate window over a healthy one.
        expect(createStudioSession.mock.calls.length).toBe(createBefore);
    });
    it("re-binds an explicit session id when the active pointer is on a different service", async () => {
        const { createStudioSession } = await import("./createStudioSession.js");
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "explicit-session",
            serviceUrl: "https://old-host.invalid",
        });
        const navBefore = mockNavigateStudioAndAwaitAck.mock.calls.length;
        const result = await openStudioTo("/studio", {
            apiKey: "test-key",
            serviceUrl: "https://test.invalid",
            sessionId: "explicit-session",
        });
        // The id matches but the tracked session is on a different service than the
        // one now configured, so don't reuse that tab: re-bind on the configured
        // service instead of navigating the stale host.
        expect(mockNavigateStudioAndAwaitAck.mock.calls.length).toBe(navBefore);
        expect(createStudioSession).toHaveBeenCalledWith(expect.objectContaining({
            sessionId: "explicit-session",
            serviceUrl: "https://test.invalid",
        }));
        expect(result.opened).toBe(true);
    });
});
